// Normalize request_id from either trigger source using $input (works for both):
// - Execute Workflow Trigger: item.json = { request_id: '...' }
// - Webhook (portal path):    item.json = { body: { request_id: '...' }, headers: {...} }
const item = $input.first().json;
const request_id = item.request_id || (item.body && item.body.request_id);
if (!request_id) throw new Error('No request_id found in trigger payload.');
return { json: { request_id } };

const quotations = $('PostgreSQL: Get All Quotations').all().map(i => i.json);
const requestData = $('PostgreSQL: Close Request').first().json;
const userData = $('PostgreSQL: Get User').first().json;
const requestId = $('Code: Normalize Request ID').first().json.request_id;

if (!quotations.length) throw new Error('No quotations found for ' + requestId);

const sorted = [...quotations].sort((a, b) => Number(a.total_price) - Number(b.total_price));
const cheapest = sorted[0];
const fastest = sorted.reduce((p, c) => (Number(c.transit_days) || 999) < (Number(p.transit_days) || 999) ? c : p);

let quoteRows = '';
sorted.forEach((q, i) => {
  const isCheapest = q.quotation_id === cheapest.quotation_id;
  const isFastest = q.quotation_id === fastest.quotation_id;
  let badges = '';
  if (isCheapest) badges += '<span style="background:#16a34a;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;margin-right:4px">🏆 BEST PRICE</span>';
  if (isFastest && q.quotation_id !== cheapest.quotation_id) badges += '<span style="background:#d97706;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px">⚡ FASTEST</span>';
  const rowBg = isCheapest ? 'background:#f0fdf4;' : '';
  quoteRows += `<tr style="${rowBg}">
    <td style="padding:12px;border-bottom:1px solid #e5e7eb"><strong>${q.forwarder_company}</strong><br><small style="color:#6b7280">${q.service_type || 'FCL'}</small></td>
    <td style="padding:12px;border-bottom:1px solid #e5e7eb;text-align:right"><strong style="font-size:18px;color:#1e3a5f">${q.currency} ${Number(q.total_price).toLocaleString()}</strong></td>
    <td style="padding:12px;border-bottom:1px solid #e5e7eb;text-align:center">${q.transit_days || 'TBD'} days</td>
    <td style="padding:12px;border-bottom:1px solid #e5e7eb;text-align:center">${q.carrier || '—'}</td>
    <td style="padding:12px;border-bottom:1px solid #e5e7eb">${badges}</td>
  </tr>`;
});

const savings = Number(sorted[sorted.length - 1].total_price) - Number(cheapest.total_price);

const emailBody = `<!DOCTYPE html><html><head><meta charset='UTF-8'></head>
<body style="font-family:Arial,sans-serif;background:#f4f4f4;margin:0;padding:0">
<div style="max-width:700px;margin:20px auto;background:#fff;border-radius:12px;overflow:hidden;border:1px solid #e5e7eb">
  <div style="background:#ffffff;padding:18px 30px;text-align:center;border-bottom:2px solid #f0f0f0"><img src="https://cargolink.sa/cargolink1.png" alt="CargoLink" style="height:52px;width:auto;display:block;margin:0 auto" /></div><div style="background:#1e3a5f;color:#fff;padding:36px;text-align:center">
    <h1 style="margin:0;font-size:26px;font-weight:900">🎯 Your 3 Quotes Are Ready!</h1>
    <p style="margin:10px 0 0;opacity:0.7;font-size:14px">CargoLink Marketplace · Request Closed</p>
  </div>
  <div style="padding:36px">
    <p style="font-size:15px;font-weight:700;color:#111">Hello ${userData.full_name},</p>
    <p style="color:#555;font-size:14px;line-height:1.6">Your freight request <b>${requestId}</b> has received 3 competitive quotations and is now closed. Compare below and choose your forwarder in the dashboard.</p>
    <div style="background:#fef3c7;border:1px solid #fcd34d;border-radius:8px;padding:16px;margin:20px 0">
      <p style="margin:0;color:#92400e;font-size:13px">💰 Best price: <b>${cheapest.currency} ${Number(cheapest.total_price).toLocaleString()}</b> from <b>${cheapest.forwarder_company}</b> · Potential savings: <b>${cheapest.currency} ${savings.toLocaleString()}</b></p>
    </div>
    <table style="width:100%;border-collapse:collapse;margin:24px 0">
      <thead><tr style="background:#1e3a5f;color:#fff">
        <th style="padding:12px;text-align:left">Forwarder</th>
        <th style="padding:12px;text-align:right">Price</th>
        <th style="padding:12px;text-align:center">Transit</th>
        <th style="padding:12px;text-align:center">Carrier</th>
        <th style="padding:12px"></th>
      </tr></thead>
      <tbody>${quoteRows}</tbody>
    </table>
    <div style="text-align:center;margin:32px 0">
      <a href="https://cargolink.sa/dashboard/shipments" style="background:#16a34a;color:#fff;padding:16px 40px;text-decoration:none;border-radius:8px;font-weight:700;font-size:15px">Compare Quotes &amp; Choose →</a>
    </div>
    <div style="background:#f0f9ff;border:1px solid #bae6fd;border-radius:8px;padding:16px">
      <p style="margin:0;font-size:13px;color:#0369a1">💬 <b>Tip:</b> Click "Chat" next to any quote in your dashboard to negotiate directly with the forwarder before locking the deal.</p>
    </div>
  </div>
  <div style="background:#f9fafb;padding:16px;text-align:center;font-size:11px;color:#9ca3af">CargoLink · Freight Marketplace · <a href="https://cargolink.sa" style="color:#9ca3af">cargolink.sa</a></div>
</div>
</body></html>`;

return {
  json: {
    user_email: userData.email,
    user_name: userData.full_name,
    request_id: requestId,
    email_body: emailBody
  }
};
